from django.utils.text import slugify


def _unique_slug(label, existing_slugs):
    base_slug = slugify(label) or uuid.uuid4().hex[:8]
    slug = base_slug
    suffix = 2
    while slug in existing_slugs:
        slug = f"{base_slug}-{suffix}"
        suffix += 1
    existing_slugs.add(slug)
    return slug


def populate_organizations(apps, schema_editor):
    Organization = apps.get_model("sav", "Organization")
    User = apps.get_model("sav", "User")
    Product = apps.get_model("sav", "Product")
    Ticket = apps.get_model("sav", "Ticket")
    SupportSession = apps.get_model("sav", "SupportSession")
    KnowledgeArticle = apps.get_model("sav", "KnowledgeArticle")
    Notification = apps.get_model("sav", "Notification")
    OfferRecommendation = apps.get_model("sav", "OfferRecommendation")
